define i5 @shl1_nsw_increment(i5 %x, i5 %y) {
  %pow2x = shl i5 1, %x
  %x1 = add i5 %pow2x, 1
  %m = mul nsw i5 %x1, %y
  ret i5 %m
}

define i5 @shl1_nsw_nsw_increment(i5 %x, i5 %y) {
  %pow2x = shl nsw i5 1, %x
  %x1 = add i5 %pow2x, 1
  %m = mul nsw i5 %y, %x1
  ret i5 %m
}
